1	/**
2	 * Phase execution engine for workflow orchestration.
3	 *
4	 * Handles executing individual phases via an AgentDriver interface,
5	 * including cold-start retry logic and MCP fallback strategies.
6	 *
7	 * The SDK import has been moved to ClaudeCodeDriver — this module
8	 * is agent-agnostic.
9	 */
10	
11	import chalk from "chalk";
12	import { execSync } from "child_process";
13	import { ShutdownManager } from "../shutdown.js";
14	import { PhaseSpinner } from "../phase-spinner.js";
15	import { Phase, ExecutionConfig, PhaseResult, QaVerdict } from "./types.js";
16	import type { QaSummary } from "./run-log-schema.js";
17	import { readAgentsMd } from "../agents-md.js";
18	import { getDriver } from "./drivers/index.js";
19	import type {
20	  AgentDriver,
21	  AgentExecutionConfig,
22	  AgentPhaseResult,
23	} from "./drivers/index.js";
24	import { classifyError } from "./error-classifier.js";
25	import { ApiError } from "../errors.js";
26	
27	/**
28	 * Natural language prompts for each phase.
29	 * Claude Code invokes the corresponding skills via natural language.
30	 */
31	const PHASE_PROMPTS: Record<Phase, string> = {
32	  spec: "Review GitHub issue #{issue} and create an implementation plan with verification criteria. Run the /spec {issue} workflow.",
33	  "security-review":
34	    "Perform a deep security analysis for GitHub issue #{issue} focusing on auth, permissions, and sensitive operations. Run the /security-review {issue} workflow.",
35	  testgen:
36	    "Generate test stubs for GitHub issue #{issue} based on the specification. Run the /testgen {issue} workflow.",
37	  exec: "Implement the feature for GitHub issue #{issue} following the spec. Run the /exec {issue} workflow.",
38	  test: "Execute structured browser-based testing for GitHub issue #{issue}. Run the /test {issue} workflow.",
39	  verify:
40	    "Verify the implementation for GitHub issue #{issue} by running commands and capturing output. Run the /verify {issue} workflow.",
41	  qa: "Review the implementation for GitHub issue #{issue} against acceptance criteria. Run the /qa {issue} workflow.",
42	  loop: "Parse test/QA findings for GitHub issue #{issue} and iterate until quality gates pass. Run the /loop {issue} workflow.",
43	  merger:
44	    "Integrate and merge completed worktrees for GitHub issue #{issue}. Run the /merger {issue} workflow.",
45	};
46	
47	/**
48	 * Self-contained prompts for non-Claude agents (Aider, Codex, etc.).
49	 * These agents don't have a skill system, so prompts must include
50	 * full instructions rather than skill invocations.
51	 */
52	const AIDER_PHASE_PROMPTS: Record<Phase, string> = {
53	  spec: `Read GitHub issue #{issue} using 'gh issue view #{issue}'.
54	Create a spec comment on the issue with:
55	1. Implementation plan
56	2. Acceptance criteria as a checklist
57	3. Risk assessment
58	Post the comment using 'gh issue comment #{issue} --body "<comment>"'.`,
59	  "security-review": `Perform a security review for GitHub issue #{issue}.
60	Read the issue with 'gh issue view #{issue}'.
61	Check for auth, permissions, injection, and sensitive data issues.
62	Post findings as a comment on the issue.`,
63	  testgen: `Generate test stubs for GitHub issue #{issue}.
64	Read the spec comments on the issue with 'gh issue view #{issue} --comments'.
65	Create test files with describe/it blocks covering the acceptance criteria.
66	Use the project's existing test framework.`,
67	  exec: `Implement the feature described in GitHub issue #{issue}.
68	Read the issue and any spec comments with 'gh issue view #{issue} --comments'.
69	Follow the implementation plan from the spec.
70	Write tests for new functionality.
71	Ensure the build passes with 'npm test' and 'npm run build'.`,
72	  test: `Test the implementation for GitHub issue #{issue}.
73	Run 'npm test' and verify all tests pass.
74	Check for edge cases and error handling.`,
75	  verify: `Verify the implementation for GitHub issue #{issue}.
76	Run relevant commands and capture their output for review.`,
77	  qa: `Review the changes for GitHub issue #{issue}.
78	Run 'npm test' and 'npm run build' to verify everything works.
79	Check each acceptance criterion from the issue comments.
80	Output a verdict: READY_FOR_MERGE, AC_MET_BUT_NOT_A_PLUS, or AC_NOT_MET
81	with format "### Verdict: <VERDICT>" followed by an explanation.`,
82	  loop: `Review test and QA findings for GitHub issue #{issue}.
83	Fix any issues identified in the QA feedback.
84	Re-run 'npm test' and 'npm run build' until all quality gates pass.`,
85	  merger: `Integrate and merge completed worktrees for GitHub issue #{issue}.
86	Ensure all branches are up to date and merge cleanly.`,
87	};
88	
89	/**
90	 * Phases that require worktree isolation.
91	 * Only `spec` runs in the main repo (planning-only, no file changes).
92	 * All other phases must run in the worktree because:
93	 * 1. They need to read/modify the worktree code
94	 * 2. Resuming a session created in a different cwd crashes the SDK
95	 */
96	const ISOLATED_PHASES: Phase[] = [
97	  "exec",
98	  "security-review",
99	  "testgen",
100	  "test",
101	  "qa",
102	  "loop",
103	];
104	
105	/**
106	 * Cold-start retry threshold in seconds.
107	 * Failures under this duration are likely Claude Code subprocess initialization
108	 * issues rather than genuine phase failures (based on empirical data: cold-start
109	 * failures consistently complete in 15-39s vs 150-310s for real work).
110	 */
111	const COLD_START_THRESHOLD_SECONDS = 60;
112	const COLD_START_MAX_RETRIES = 2;
113	
114	/**
115	 * Spec-specific retry configuration.
116	 * Spec failures have a higher failure rate (~8.6%) than other phases due to
117	 * transient GitHub API issues and rate limits. One extra retry with backoff
118	 * recovers most of these without user intervention.
119	 */
120	/** @internal Exported for testing only */
121	export const SPEC_RETRY_BACKOFF_MS = 5000;
122	/** @internal Exported for testing only */
123	export const SPEC_EXTRA_RETRIES = 1;
124	
125	export function parseQaVerdict(output: string): QaVerdict | null {
126	  if (!output) return null;
127	
128	  // Match various verdict formats:
129	  // - "### Verdict: X" (markdown header)
130	  // - "**Verdict:** X" (bold label with colon inside)
131	  // - "**Verdict:** **X**" (bold label and bold value)
132	  // - "Verdict: X" (plain)
133	  // Case insensitive, handles optional markdown formatting
134	  const verdictMatch = output.match(
135	    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
136	  );
137	
138	  if (!verdictMatch) return null;
139	
140	  // Normalize to uppercase with underscores
141	  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
142	  return verdict;
143	}
144	
145	/**
146	 * Parse condensed QA summary from QA phase output (#434).
147	 *
148	 * Handles multiple AC table formats produced by the QA skill:
149	 * - 5-column: | AC-N | source | desc | STATUS | notes |
150	 * - 4-column: | AC-N | desc | STATUS | notes |
151	 * - 3-column: | AC-N | desc | STATUS |
152	 *
153	 * Status cells may contain emoji prefixes (✅ MET), shorthand
154	 * (PARTIAL), or trailing text (MET — explanation).
155	 *
156	 * @internal Exported for testing only
157	 */
158	export function parseQaSummary(output: string): QaSummary | null {
159	  if (!output) return null;
160	
161	  // Anchored pattern: cell content starts with optional emoji, then status keyword
162	  // Uses alternation (not character class) to avoid ESLint no-misleading-character-class
163	  const STATUS_CELL =
164	    /^(?:\u2705|\u274C|\u26A0\uFE0F|\u2B50|\u2139\uFE0F|\u2753|\u2757)?\s*(MET|NOT_MET|PARTIALLY_MET|PARTIAL|PENDING|N\/A)\b/i;
165	
166	  const lines = output.split("\n");
167	  const acRows = lines.filter((line) => /^\s*\|\s*\*?\*?AC-\d+/.test(line));
168	
169	  if (acRows.length === 0) return null;
170	
171	  let acMet = 0;
172	  let acTotal = 0;
173	
174	  for (const row of acRows) {
175	    const cells = row
176	      .split("|")
177	      .map((c) => c.trim())
178	      .filter(Boolean);
179	
180	    // Scan cells right-to-left to find the status cell
181	    let found = false;
182	    for (let i = cells.length - 1; i >= 1; i--) {
183	      const match = cells[i].match(STATUS_CELL);
184	      if (match) {
185	        const status = match[1].toUpperCase();
186	        acTotal++;
187	        if (status === "MET") acMet++;
188	        found = true;
189	        break;
190	      }
191	    }
192	    // Row with AC-N but no parseable status is skipped
193	    if (!found) continue;
194	  }
195	
196	  if (acTotal === 0) return null;
197	
198	  const gaps = parseListSection(output, /\*\*(?:Issues|Gaps)/);
199	  const suggestions = parseListSection(output, /\*\*Suggestions/);
200	
201	  return { acMet, acTotal, gaps, suggestions };
202	}
203	
204	/**
205	 * Parse a markdown bullet list section, filtering out "None" variants.
206	 */
207	function parseListSection(output: string, headerPattern: RegExp): string[] {
208	  const items: string[] = [];
209	  const lines = output.split("\n");
210	
211	  let inSection = false;
212	  for (const line of lines) {
213	    if (headerPattern.test(line)) {
214	      // If the header line itself contains a bullet (inline), capture it
215	      inSection = true;
216	      continue;
217	    }
218	
219	    if (inSection) {
220	      // Section ends at next markdown header or bold label
221	      if (/^#{1,4}\s/.test(line) || /^\*\*[^*]+\*\*:/.test(line)) {
222	        break;
223	      }
224	
225	      const bulletMatch = line.match(/^\s*[-*]\s+(.+)/);
226	      if (bulletMatch) {
227	        const trimmed = bulletMatch[1].trim();
228	        // Filter "None", "None found", "None — text", etc.
229	        if (trimmed && !/^None\b/i.test(trimmed)) {
230	          items.push(trimmed);
231	        }
232	      } else if (line.trim() === "") {
233	        continue;
234	      } else {
235	        break;
236	      }
237	    }
238	  }
239	
240	  return items;
241	}
242	
243	/**
244	 * Format duration in human-readable format
245	 */
246	export function formatDuration(seconds: number): string {
247	  if (seconds < 60) {
248	    return `${seconds.toFixed(1)}s`;
249	  }
250	  const mins = Math.floor(seconds / 60);
251	  const secs = seconds % 60;
252	  return `${mins}m ${secs.toFixed(0)}s`;
253	}
254	
255	/**
256	 * Check whether the exec phase produced any changes in the worktree.
257	 * Returns true if HEAD has commits unique to it relative to origin/main
258	 * OR uncommitted work is present.
259	 *
260	 * Uses `git rev-list --count origin/main..HEAD` (commits reachable from HEAD
261	 * but not origin/main) instead of `git diff origin/main..HEAD`, because the
262	 * two-dot diff also fires in reverse when origin/main has advanced past HEAD
263	 * — on stale branches that would falsely report "has commits" even when the
264	 * exec phase produced nothing, reintroducing the bug #534 is fixing.
265	 *
266	 * Fails open (returns true) on git errors — a missing origin ref is better
267	 * diagnosed as a real zero-diff run than as a false phase failure.
268	 *
269	 * @internal Exported for testing only.
270	 */
271	export function hasExecChanges(cwd: string): boolean {
272	  let commitsAhead: boolean;
273	  try {
274	    const count = execSync("git rev-list --count origin/main..HEAD", {
275	      cwd,
276	      stdio: "pipe",
277	    })
278	      .toString()
279	      .trim();
280	    commitsAhead = Number.parseInt(count, 10) > 0;
281	  } catch {
282	    return true;
283	  }
284	  if (commitsAhead) return true;
285	  try {
286	    const porcelain = execSync("git status --porcelain", { cwd, stdio: "pipe" })
287	      .toString()
288	      .trim();
289	    return porcelain.length > 0;
290	  } catch {
291	    return true;
292	  }
293	}
294	
295	/**
296	 * Map a successful AgentPhaseResult to a PhaseResult, applying phase-specific
297	 * guards that catch agent sessions which returned success without producing
298	 * usable work (#534):
299	 *
300	 * - `qa`: fails when no parseable verdict is found (empty or malformed output).
301	 * - `exec`: fails when no commits and no uncommitted changes exist.
302	 *
303	 * @internal Exported for testing only.
304	 */
305	export function mapAgentSuccessToPhaseResult(
306	  phase: Phase,
307	  agentResult: AgentPhaseResult,
308	  durationSeconds: number,
309	  cwd: string,
310	): PhaseResult & { sessionId?: string } {
311	  const tails = {
312	    stderrTail: agentResult.stderrTail,
313	    stdoutTail: agentResult.stdoutTail,
314	    exitCode: agentResult.exitCode,
315	  };
316	
317	  if (phase === "qa") {
318	    const verdict = agentResult.output
319	      ? parseQaVerdict(agentResult.output)
320	      : null;
321	    const summary = agentResult.output
322	      ? (parseQaSummary(agentResult.output) ?? undefined)
323	      : undefined;
324	    if (
325	      verdict &&
326	      verdict !== "READY_FOR_MERGE" &&
327	      verdict !== "NEEDS_VERIFICATION"
328	    ) {
329	      return {
330	        phase,
331	        success: false,
332	        durationSeconds,
333	        error: `QA verdict: ${verdict}`,
334	        sessionId: agentResult.sessionId,
335	        output: agentResult.output,
336	        verdict,
337	        summary,
338	        ...tails,
339	      };
340	    }
341	    if (!verdict) {
342	      // #534: a null verdict (empty or unparseable output) is not success.
343	      return {
344	        phase,
345	        success: false,
346	        durationSeconds,
347	        error: "QA completed without a parseable verdict",
348	        sessionId: agentResult.sessionId,
349	        output: agentResult.output,
350	        summary,
351	        ...tails,
352	      };
353	    }
354	    return {
355	      phase,
356	      success: true,
357	      durationSeconds,
358	      sessionId: agentResult.sessionId,
359	      output: agentResult.output,
360	      verdict,
361	      summary,
362	      ...tails,
363	    };
364	  }
365	
366	  if (phase === "exec" && !hasExecChanges(cwd)) {
367	    // #534: an exec phase that produced nothing is not success.
368	    return {
369	      phase,
370	      success: false,
371	      durationSeconds,
372	      error: "exec produced no changes (no commits, no uncommitted work)",
373	      sessionId: agentResult.sessionId,
374	      output: agentResult.output,
375	      ...tails,
376	    };
377	  }
378	
379	  return {
380	    phase,
381	    success: true,
382	    durationSeconds,
383	    sessionId: agentResult.sessionId,
384	    output: agentResult.output,
385	    ...tails,
386	  };
387	}
388	
389	/**
390	 * Get the prompt for a phase with the issue number substituted.
391	 * Selects self-contained prompts for non-Claude agents.
392	 * Includes AGENTS.md content as context so non-Claude agents
393	 * receive project conventions and workflow instructions.
394	 *
395	 * @internal Exported for testing only
396	 */
397	export async function getPhasePrompt(
398	  phase: Phase,
399	  issueNumber: number,
400	  agent?: string,
401	  promptContext?: string,
402	): Promise<string> {
403	  const prompts =
404	    agent && agent !== "claude-code" ? AIDER_PHASE_PROMPTS : PHASE_PROMPTS;
405	  let basePrompt = prompts[phase].replace(/\{issue\}/g, String(issueNumber));
406	
407	  // Append phase-specific context (e.g., QA findings for loop phase)
408	  if (promptContext) {
409	    basePrompt += `\n\n---\n\n${promptContext}`;
410	  }
411	
412	  // Include AGENTS.md content in the prompt context for non-Claude agent compatibility.
413	  // Claude reads CLAUDE.md natively, but other agents (Aider, Codex, Gemini CLI)
414	  // rely on AGENTS.md for project context.
415	  const agentsMd = await readAgentsMd();
416	  if (agentsMd) {
417	    return `Project context (from AGENTS.md):\n\n${agentsMd}\n\n---\n\n${basePrompt}`;
418	  }
419	
420	  return basePrompt;
421	}
422	
423	/**
424	 * Execute a single phase for an issue using the configured AgentDriver.
425	 */
426	async function executePhase(
427	  issueNumber: number,
428	  phase: Phase,
429	  config: ExecutionConfig,
430	  sessionId?: string,
431	  worktreePath?: string,
432	  shutdownManager?: ShutdownManager,
433	  spinner?: PhaseSpinner,
434	): Promise<PhaseResult & { sessionId?: string }> {
435	  const startTime = Date.now();
436	
437	  const prompt = await getPhasePrompt(
438	    phase,
439	    issueNumber,
440	    config.agent,
441	    config.promptContext,
442	  );
443	
444	  if (config.dryRun) {
445	    // Dry run - show the prompt that would be sent, then return
446	    if (config.verbose) {
447	      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
448	      console.log(chalk.gray(`    Prompt: ${prompt}`));
449	    }
450	    return {
451	      phase,
452	      success: true,
453	      durationSeconds: 0,
454	      output: prompt,
455	    };
456	  }
457	
458	  if (config.verbose) {
459	    console.log(chalk.gray(`    Prompt: ${prompt}`));
460	    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
461	      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
462	    }
463	  }
464	
465	  // Determine working directory and environment
466	  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
467	  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
468	
469	  // Resolve file context for file-oriented drivers (e.g., Aider --file)
470	  let files: string[] | undefined;
471	  if (config.agent && config.agent !== "claude-code") {
472	    try {
473	      const output = execSync("git diff --name-only main...HEAD", {
474	        cwd,
475	        encoding: "utf-8",
476	        stdio: ["pipe", "pipe", "pipe"],
477	      }).trim();
478	      if (output) {
479	        files = output.split("\n").filter(Boolean);
480	      }
481	    } catch {
482	      // No changed files or git error — proceed without file context
483	    }
484	  }
485	
486	  // Check if shutdown is in progress
487	  if (shutdownManager?.shuttingDown) {
488	    return {
489	      phase,
490	      success: false,
491	      durationSeconds: 0,
492	      error: "Shutdown in progress",
493	    };
494	  }
495	
496	  // Create abort controller for timeout
497	  const abortController = new AbortController();
498	  const timeoutId = setTimeout(() => {
499	    abortController.abort();
500	  }, config.phaseTimeout * 1000);
501	
502	  // Register abort controller with shutdown manager for graceful shutdown
503	  // Uses add/remove to support concurrent phase execution (#404)
504	  if (shutdownManager) {
505	    shutdownManager.addAbortController(abortController);
506	  }
507	
508	  // Build environment with worktree isolation variables
509	  const env: Record<string, string> = {
510	    ...process.env,
511	    CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
512	  };
513	
514	  // Set worktree isolation environment variables
515	  if (shouldUseWorktree) {
516	    env.SEQUANT_WORKTREE = worktreePath;
517	    env.SEQUANT_ISSUE = String(issueNumber);
518	  }
519	
520	  // Set orchestration context for skills to detect they're part of a workflow
521	  // Skills can check these to skip redundant pre-flight checks
522	  env.SEQUANT_ORCHESTRATOR = "sequant-run";
523	  env.SEQUANT_PHASE = phase;
524	
525	  // Propagate issue type for skills to adapt behavior (e.g., lighter QA for docs)
526	  if (config.issueType) {
527	    env.SEQUANT_ISSUE_TYPE = config.issueType;
528	  }
529	
530	  // Pass QA context to loop phase so it doesn't need to reconstruct from GitHub (#488)
531	  if (config.lastVerdict) {
532	    env.SEQUANT_LAST_VERDICT = config.lastVerdict;
533	  }
534	  if (config.failedAcs) {
535	    env.SEQUANT_FAILED_ACS = config.failedAcs;
536	  }
537	
538	  // Propagate parallel isolation mode to exec skill (#485)
539	  if (config.isolateParallel) {
540	    env.SEQUANT_ISOLATE_PARALLEL = "true";
541	  }
542	
543	  // Track whether we're actively streaming verbose output
544	  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
545	  // (Issue #283: ora's stop() clears the current line, which can truncate output when
546	  // pause/resume is called for every chunk in rapid succession)
547	  let verboseStreamingActive = false;
548	
549	  // Safety: never resume a session when worktree isolation is active.
550	  // Even if THIS phase doesn't use the worktree, a previous phase may have
551	  // created the session there. Resuming from a different cwd crashes the SDK
552	  // (exit code 1). ISOLATED_PHASES prevents this by design, but this guard
553	  // catches edge cases (e.g. a new phase added without updating ISOLATED_PHASES).
554	  const canResume = sessionId && !worktreePath;
555	
556	  // Build AgentExecutionConfig for the driver
557	  const agentConfig: AgentExecutionConfig = {
558	    cwd,
559	    env,
560	    abortSignal: abortController.signal,
561	    phaseTimeout: config.phaseTimeout,
562	    verbose: config.verbose,
563	    mcp: config.mcp,
564	    sessionId: canResume ? sessionId : undefined,
565	    files,
566	    onOutput: config.verbose
567	      ? (text: string) => {
568	          if (!verboseStreamingActive) {
569	            spinner?.pause();
570	            verboseStreamingActive = true;
571	          }
572	          process.stdout.write(chalk.gray(text));
573	        }
574	      : undefined,
575	    onStderr: config.verbose
576	      ? (data: string) => {
577	          if (!verboseStreamingActive) {
578	            spinner?.pause();
579	            verboseStreamingActive = true;
580	          }
581	          process.stderr.write(chalk.red(data));
582	        }
583	      : undefined,
584	  };
585	
586	  // Resolve driver from config or default
587	  const driver: AgentDriver = getDriver(config.agent, {
588	    aiderSettings: config.aiderSettings,
589	  });
590	
591	  const agentResult = await driver.executePhase(prompt, agentConfig);
592	
593	  // Resume spinner after execution completes (if we paused it)
594	  if (verboseStreamingActive) {
595	    spinner?.resume();
596	  }
597	
598	  clearTimeout(timeoutId);
599	
600	  // Remove this specific abort controller from shutdown manager
601	  if (shutdownManager) {
602	    shutdownManager.removeAbortController(abortController);
603	  }
604	
605	  const durationSeconds = (Date.now() - startTime) / 1000;
606	
607	  if (agentResult.success) {
608	    return mapAgentSuccessToPhaseResult(
609	      phase,
610	      agentResult,
611	      durationSeconds,
612	      cwd,
613	    );
614	  }
615	
616	  return {
617	    phase,
618	    success: false,
619	    durationSeconds,
620	    error: agentResult.error,
621	    sessionId: agentResult.sessionId,
622	    stderrTail: agentResult.stderrTail,
623	    stdoutTail: agentResult.stdoutTail,
624	    exitCode: agentResult.exitCode,
625	  };
626	}
627	
628	/**
629	 * Execute a phase with automatic retry for cold-start failures and MCP fallback.
630	 *
631	 * Retry strategy:
632	 * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
633	 * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
634	 *    can fail on first run due to cold-cache issues)
635	 *
636	 * The MCP fallback is safe because MCP servers are optional enhancements, not required
637	 * for core functionality.
638	 */
639	/**
640	 * @internal Exported for testing only
641	 */
642	export async function executePhaseWithRetry(
643	  issueNumber: number,
644	  phase: Phase,
645	  config: ExecutionConfig,
646	  sessionId?: string,
647	  worktreePath?: string,
648	  shutdownManager?: ShutdownManager,
649	  spinner?: PhaseSpinner,
650	  /** @internal Injected for testing — defaults to module-level executePhase */
651	  executePhaseFn: typeof executePhase = executePhase,
652	  /** @internal Injected for testing — defaults to setTimeout-based delay */
653	  delayFn: (ms: number) => Promise<void> = (ms) =>
654	    new Promise((resolve) => setTimeout(resolve, ms)),
655	): Promise<PhaseResult & { sessionId?: string }> {
656	  // Skip retry logic if explicitly disabled
657	  if (config.retry === false) {
658	    return executePhaseFn(
659	      issueNumber,
660	      phase,
661	      config,
662	      sessionId,
663	      worktreePath,
664	      shutdownManager,
665	      spinner,
666	    );
667	  }
668	
669	  // Skip cold-start retries for `loop` phase (#488).
670	  // Loop is always a re-run after a failed QA — never a first boot.
671	  // Failures at 47-51s are genuine skill failures, not cold-start issues.
672	  // Without this guard, 2 cold-start retries + 1 MCP fallback = 3 wasted spawns per loop.
673	  const skipColdStartRetry = phase === "loop";
674	
675	  let lastResult: PhaseResult & { sessionId?: string };
676	
677	  if (skipColdStartRetry) {
678	    // Single attempt — no cold-start retry loop
679	    lastResult = await executePhaseFn(
680	      issueNumber,
681	      phase,
682	      config,
683	      sessionId,
684	      worktreePath,
685	      shutdownManager,
686	      spinner,
687	    );
688	
689	    if (lastResult.success) {
690	      return lastResult;
691	    }
692	  } else {
693	    // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
694	    for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
695	      lastResult = await executePhaseFn(
696	        issueNumber,
697	        phase,
698	        config,
699	        sessionId,
700	        worktreePath,
701	        shutdownManager,
702	        spinner,
703	      );
704	
705	      const duration = lastResult.durationSeconds ?? 0;
706	
707	      // Success → return immediately
708	      if (lastResult.success) {
709	        return lastResult;
710	      }
711	
712	      // Genuine failure (took long enough to be real work) → skip cold-start retries.
713	      // Use error classification (AC-9): if the error is retryable (e.g., API
714	      // rate limit, transient 503), allow one more attempt even for genuine failures.
715	      if (duration >= COLD_START_THRESHOLD_SECONDS) {
716	        const typedError = classifyError(
717	          lastResult.stderrTail ?? [],
718	          lastResult.exitCode,
719	        );
720	        if (typedError.isRetryable && attempt < COLD_START_MAX_RETRIES) {
721	          if (config.verbose) {
722	            const label =
723	              typedError instanceof ApiError
724	                ? `API error (status ${typedError.metadata.statusCode ?? "unknown"})`
725	                : typedError.name;
726	            console.log(
727	              chalk.yellow(
728	                `\n    ⟳ Retryable error: ${label}, retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
729	              ),
730	            );
731	          }
732	          continue;
733	        }
734	        if (phase === "spec") {
735	          break;
736	        }
737	        return lastResult;
738	      }
739	
740	      // Cold-start failure detected — retry
741	      if (attempt < COLD_START_MAX_RETRIES) {
742	        if (config.verbose) {
743	          console.log(
744	            chalk.yellow(
745	              `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
746	            ),
747	          );
748	        }
749	      }
750	    }
751	  }
752	
753	  // Capture the original error for better diagnostics
754	  const originalError = lastResult!.error;
755	
756	  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
757	  // This handles npx-based MCP servers that fail on first run due to cold-cache issues.
758	  // Skip for `loop` phase — MCP is never the cause of loop failures (#488).
759	  if (config.mcp && !lastResult!.success && !skipColdStartRetry) {
760	    console.log(
761	      chalk.yellow(
762	        `\n    ! Phase failed with MCP enabled, retrying without MCP...`,
763	      ),
764	    );
765	
766	    // Create config copy with MCP disabled
767	    const configWithoutMcp: ExecutionConfig = {
768	      ...config,
769	      mcp: false,
770	    };
771	
772	    const retryResult = await executePhaseFn(
773	      issueNumber,
774	      phase,
775	      configWithoutMcp,
776	      sessionId,
777	      worktreePath,
778	      shutdownManager,
779	      spinner,
780	    );
781	
782	    if (retryResult.success) {
783	      console.log(
784	        chalk.green(
785	          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
786	        ),
787	      );
788	      return retryResult;
789	    }
790	
791	    // Update lastResult for Phase 3 (spec retry)
792	    lastResult = retryResult;
793	
794	    // Non-spec phases: return original error after MCP fallback exhausted
795	    if (phase !== "spec") {
796	      return {
797	        ...lastResult!,
798	        error: originalError,
799	      };
800	    }
801	  }
802	
803	  // Phase 3: Spec-specific retry — spec has a higher transient failure rate
804	  // than other phases (~8.6%), so one extra retry with backoff recovers most cases.
805	  if (phase === "spec" && !lastResult!.success) {
806	    for (let i = 0; i < SPEC_EXTRA_RETRIES; i++) {
807	      console.log(
808	        chalk.yellow(
809	          `\n    ⟳ Spec phase failed, retrying with ${SPEC_RETRY_BACKOFF_MS}ms backoff... (spec retry ${i + 1}/${SPEC_EXTRA_RETRIES})`,
810	        ),
811	      );
812	
813	      await delayFn(SPEC_RETRY_BACKOFF_MS);
814	
815	      const specRetryResult = await executePhaseFn(
816	        issueNumber,
817	        phase,
818	        config,
819	        sessionId,
820	        worktreePath,
821	        shutdownManager,
822	        spinner,
823	      );
824	
825	      if (specRetryResult.success) {
826	        console.log(chalk.green(`    ✓ Spec phase succeeded on retry`));
827	        return specRetryResult;
828	      }
829	
830	      lastResult = specRetryResult;
831	    }
832	
833	    // All spec retries exhausted — return with original error for diagnostics
834	    return {
835	      ...lastResult!,
836	      error: originalError,
837	    };
838	  }
839	
840	  return lastResult!;
841	}
